script.text:

function active$FormUnit(f) {f.add_onResponseComplete(on$FormUnit$ResponseComplete);}
function close$FormUnit(f) {try {f.remove_onResponseComplete(on$FormUnit$ResponseComplete)} catch (ex) {}}
function on$FormUnit$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_dvcs');
      var o = f.getItem('ma_dvcs');
      if(f._checked && ($func.trim(o.value).indexOf(' ', 0) >= 0 || o.value.indexOf('.', 0) >= 0)) {
        var msg = (f._language == 'v' ? 'Trường <span class="Highlight">{0}</span> không được phép có khoảng trắng hoặc chứa ký tự: <span class="Highlight">[.]</span>.' : 'Field <span class="Highlight">{0}</span> cannot contain blank or any of the following character: <span class="Highlight">[.]</span>.');
        msg = String.format(msg, o.field.Label);
        $message.show(msg, String.format('$find(\'{0}\').focus(\'{1}\');', f._id, o.field.Name));
        f._checked = false;
      }
      break;
    default:
      break;
  }
}      

      &ScriptIrregular;
